def get_user(uid):
    # 个人用户信息
    url = f"https://www.haijiao.com/api/user/info/{uid}"
    headers = {
        "Host": "www.haijiao.com",
        "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:125.0) Gecko/20100101 Firefox/125.0",
        "Accept": "application/json, text/plain, */*",
        "Connection": "keep-alive",
        "Referer": f"https://www.haijiao.com/homepage/{uid}",
    }
    with session.get(url=url, headers=headers) as resp:
        content = resp.json()
        # print(content)
        data = b64decode(b64decode(b64decode(content["data"]).decode()).decode()).decode()
        # print(data)
        return json.loads(data)["user"]
